10	export function processScenario(scenario: any): unknown {
11	  const step = scenario.steps[0];
12	  const itemsTotal = step.items.reduce(
13	    (total: number, item: { type: string }) => total + BASE_PREMIUMS[item.type],
14	    0,
15	  );
16	  const premium = (itemsTotal * FIRST_INSURANCE_PERCENT) / 100 + PROCESSING_FEE;
17	  return { results: [{ premium }] };
18	}
